sh -c 'set -e; mkdir -p "$HOME/.claude"; printf %s '"'"''"'"' | base64 -d > "$HOME/.claude/statusline-command.sh"; chmod +x "$HOME/.claude/statusline-command.sh"; SETTINGS="$HOME/.claude/settings.json"; [ -f "$SETTINGS" ] || echo "{}" > "$SETTINGS"; if command -v jq >/dev/null 2>&1; then tmp=$(mktemp); jq --arg cmd "sh $HOME/.claude/statusline-command.sh" '"'"'.statusLine = {type:"command", command:$cmd}'"'"' "$SETTINGS" > "$tmp" && mv "$tmp" "$SETTINGS"; else python3 -c '"'"'import json,os,sys
p=os.path.expanduser("~/.claude/settings.json")
try:
 d=json.load(open(p))
except Exception:
 d={}
d["statusLine"]={"type":"command","command":"sh "+os.path.expanduser("~/.claude/statusline-command.sh")}
json.dump(d,open(p,"w"),indent=2)'"'"'; fi; echo "Statusline installed. Restart Claude Code to see it."'
